@dataclass
class CartItem:
    product_id: str
    name: str
    price: Decimal
    quantity: int
    taxable: bool = True
    
    def __post_init__(self):
        if not isinstance(self.price, Decimal):
            self.price = Decimal(str(self.price))
        if self.quantity <= 0:
            raise ValueError("Quantity must be positive")
        if self.price < 0:
            raise ValueError("Price cannot be negative")


