class InventoryService:
    def __init__(self, inventory: Dict[str, int]):
        self.inventory = inventory
    
    def check_availability(self, product_id: str, quantity: int) -> bool:
        return self.inventory.get(product_id, 0) >= quantity
    
    def reserve_items(self, product_id: str, quantity: int) -> bool:
        if self.check_availability(product_id, quantity):
            self.inventory[product_id] -= quantity
            return True
        return False


class DiscountService:
    def __init__(self, discount_codes: Dict[str, DiscountCode]):
        self.discount_codes = discount_codes
    
    def get_discount_code(self, code: str) -> Optional[DiscountCode]:
        return self.discount_codes.get(code.upper())
    
    def mark_code_used(self, code: str, user_id: str):
        discount = self.discount_codes.get(code.upper())
        if discount and discount.single_use:
            discount.used_by.append(user_id)


class PaymentGateway:
    def __init__(self):
        self.processed_payments = {}
    
    def process_payment(self, user_id: str, amount: Decimal, payment_method: Dict) -> PaymentResult:
        if amount <= 0:
            return PaymentResult(
                success=False,
                transaction_id=None,
                error_message="Invalid payment amount"
            )
        
        card_number = payment_method.get('card_number', '')
        if not self._validate_card(card_number):
            return PaymentResult(
                success=False,
                transaction_id=None,
                error_message="Invalid card number"
            )
        
        transaction_id = f"TXN-{user_id}-{datetime.now().timestamp()}"
        self.processed_payments[transaction_id] = {
            'user_id': user_id,
            'amount': amount,
            'timestamp': datetime.now()
        }
        
        return PaymentResult(
            success=True,
            transaction_id=transaction_id,
            error_message=None
        )
    
    def _validate_card(self, card_number: str) -> bool:
        card_number = re.sub(r'\s+', '', card_number)
        return len(card_number) >= 13 and card_number.isdigit()


class OrderRepository:
    def __init__(self):
        self.orders = {}
        self.order_counter = 1000
    
    def create_order(self, order: Order) -> str:
        self.orders[order.order_id] = order
        return order.order_id
    
    def get_next_order_id(self) -> str:
        self.order_counter += 1
        return f"ORD-{self.order_counter}"


class CheckoutService:
    def __init__(
        self,
        inventory_service: InventoryService,
        discount_service: DiscountService,
        payment_gateway: PaymentGateway,
        order_repository: OrderRepository,
        tax_rate: Decimal = Decimal('0.08')
    ):
        self.inventory_service = inventory_service
        self.discount_service = discount_service
        self.payment_gateway = payment_gateway
        self.order_repository = order_repository
        self.tax_rate = tax_rate
    
    def process_checkout(
        self,
        user: User,
        cart_items: List[CartItem],
        discount_code: Optional[str],
        payment_method: Dict
    ) -> Order:
        validated_cart = self._validate_cart(cart_items)
        
        discounted_cart = self._apply_discount(validated_cart, discount_code, user)
        
        tax_calculation = self._calculate_tax(discounted_cart)
        
        payment_result = self._process_payment(user, tax_calculation, payment_method)
        
        order = self._create_order(user, tax_calculation, payment_result)
        
        if discount_code:
            self.discount_service.mark_code_used(discount_code, user.user_id)
        
        return order
    
    def _validate_cart(self, cart_items: List[CartItem]) -> ValidatedCart:
        if not cart_items:
            raise ValidationError("Cart is empty")
        
        if len(cart_items) > 100:
            raise ValidationError("Cart exceeds maximum item limit")
        
        seen_products = set()
        for item in cart_items:
            if item.product_id in seen_products:
                raise ValidationError(f"Duplicate product in cart: {item.product_id}")
            seen_products.add(item.product_id)
            
            if item.quantity > 1000:
                raise ValidationError(f"Quantity exceeds maximum for product: {item.product_id}")
            
            if not self.inventory_service.check_availability(item.product_id, item.quantity):
                raise ValidationError(f"Insufficient inventory for product: {item.product_id}")
        
        subtotal = Decimal('0')
        for item in cart_items:
            item_total = item.price * item.quantity
            if item_total < 0:
                raise ValidationError(f"Invalid item total for product: {item.product_id}")
            subtotal += item_total
        
        subtotal = subtotal.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
        
        if subtotal > Decimal('1000000'):
            raise ValidationError("Cart total exceeds maximum allowed amount")
        
        return ValidatedCart(items=cart_items, subtotal=subtotal)
    
    def _apply_discount(
        self,
        validated_cart: ValidatedCart,
        discount_code: Optional[str],
        user: User
    ) -> DiscountedCart:
        if not discount_code:
            return DiscountedCart(
                validated_cart=validated_cart,
                discount_code=None,
                discount_amount=Decimal('0'),
                total_after_discount=validated_cart.subtotal
            )
        
        discount_code = discount_code.strip().upper()
        
        discount = self.discount_service.get_discount_code(discount_code)
        if not discount:
            raise DiscountError("Invalid discount code")
        
        if not discount.active:
            raise DiscountError("Discount code is not active")
        
        if user.tier not in discount.allowed_tiers:
            raise DiscountError("You are not authorized to use this discount code")
        
        if discount.single_use and user.user_id in discount.used_by:
            raise DiscountError("Discount code has already been used")
        
        if validated_cart.subtotal < discount.min_purchase:
            raise DiscountError(
                f"Minimum purchase of {discount.min_purchase} required for this discount code"
            )
        
        discount_amount = Decimal('0')
        if discount.discount_type == DiscountType.PERCENTAGE:
            if discount.value < 0 or discount.value > 100:
                raise DiscountError("Invalid discount percentage")
            discount_amount = (validated_cart.subtotal * discount.value / Decimal('100'))
        elif discount.discount_type == DiscountType.FIXED:
            if discount.value < 0:
                raise DiscountError("Invalid discount amount")
            discount_amount = discount.value
        
        if discount.max_discount:
            discount_amount = min(discount_amount, discount.max_discount)
        
        discount_amount = min(discount_amount, validated_cart.subtotal)
        
        discount_amount = discount_amount.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
        
        total_after_discount = validated_cart.subtotal - discount_amount
        total_after_discount = total_after_discount.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
        
        if total_after_discount < 0:
            raise DiscountError("Invalid discount calculation")
        
        return DiscountedCart(
            validated_cart=validated_cart,
            discount_code=discount_code,
            discount_amount=discount_amount,
            total_after_discount=total_after_discount
        )
    
    def _calculate_tax(self, discounted_cart: DiscountedCart) -> TaxCalculation:
        if self.tax_rate < 0 or self.tax_rate > 1:
            raise TaxError("Invalid tax rate")
        
        taxable_amount = Decimal('0')
        for item in discounted_cart.validated_cart.items:
            if item.taxable:
                taxable_amount += item.price * item.quantity
        
        taxable_amount = taxable_amount.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
        
        discount_ratio = Decimal('1')
        if discounted_cart.validated_cart.subtotal > 0:
            discount_ratio = discounted_cart.total_after_discount / discounted_cart.validated_cart.subtotal
        
        taxable_amount_after_discount = taxable_amount * discount_ratio
        taxable_amount_after_discount = taxable_amount_after_discount.quantize(
            Decimal('0.01'), rounding=ROUND_HALF_UP
        )
        
        tax_amount = taxable_amount_after_discount * self.tax_rate
        tax_amount = tax_amount.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
        
        total_with_tax = discounted_cart.total_after_discount + tax_amount
        total_with_tax = total_with_tax.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
        
        if total_with_tax < 0:
            raise TaxError("Invalid tax calculation")
        
        return TaxCalculation(
            discounted_cart=discounted_cart,
            tax_rate=self.tax_rate,
            tax_amount=tax_amount,
            total_with_tax=total_with_tax
        )
    
    def _process_payment(
        self,
        user: User,
        tax_calculation: TaxCalculation,
        payment_method: Dict
    ) -> PaymentResult:
        if not payment_method:
            raise PaymentError("Payment method is required")
        
        if tax_calculation.total_with_tax <= 0:
            raise PaymentError("Invalid payment amount")
        
        payment_result = self.payment_gateway.process_payment(
            user.user_id,
            tax_calculation.total_with_tax,
            payment_method
        )
        
        if not payment_result.success:
            raise PaymentError(f"Payment failed: {payment_result.error_message}")
        
        return payment_result
    
    def _create_order(
        self,
        user: User,
        tax_calculation: TaxCalculation,
        payment_result: PaymentResult
    ) -> Order:
        order_id = self.order_repository.get_next_order_id()
        
        for item in tax_calculation.discounted_cart.validated_cart.items:
            if not self.inventory_service.reserve_items(item.product_id, item.quantity):
                raise OrderError(f"Failed to reserve inventory for product: {item.product_id}")
        
        order = Order(
            order_id=order_id,
            user_id=user.user_id,
            items=tax_calculation.discounted_cart.validated_cart.items,
            subtotal=tax_calculation.discounted_cart.validated_cart.subtotal,
            discount_code=tax_calculation.discounted_cart.discount_code,
            discount_amount=tax_calculation.discounted_cart.discount_amount,
            tax_amount=tax_calculation.tax_amount,
            total=tax_calculation.total_with_tax,
            payment_status=PaymentStatus.COMPLETED,
            transaction_id=payment_result.transaction_id,
            created_at=datetime.now()
        )
        
        self.order_repository.create_order(order)
        
        return order


